SELECT tracker_name, loading_exit, next_dar_entry, next_loading_entry, (SELECT COALESCE(json_agg(json_build_object('name', g.geofence_name, 'in', g.in_time_dt, 'out', g.out_time_dt)), '[]') FROM geofence_visits g WHERE g.tracker_id = t.tracker_id AND g.in_time_dt >= t.loading_exit AND g.in_time_dt <= COALESCE(t.next_dar_entry, t.next_loading_entry, NOW())) as raw_visits FROM tat_trips_data t WHERE dest_exit IS NULL AND (next_dar_entry IS NOT NULL OR next_loading_entry IS NOT NULL) ORDER BY loading_exit ASC LIMIT 5
